frappe.ui.form.on("Project", {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button(
                __("Generate Component Masters"),
                function () {
                    frappe.confirm(
                        __(
                            "This will create Project Component Master records for all active BOMs in project <b>{0}</b>.<br><br>" +
                            "Existing Component Masters will be skipped (no duplicates).<br><br>" +
                            "Proceed?",
                            [frm.doc.name]
                        ),
                        function () {
                            frappe.call({
                                method: "clevertech.project_component_master.bulk_generation.generate_component_masters_from_boms",
                                args: {
                                    project: frm.doc.name,
                                },
                                freeze: true,
                                freeze_message: __(
                                    "Generating Component Masters..."
                                ),
                                callback(r) {
                                    if (r.message) {
                                        let result = r.message;
                                        show_generation_result(
                                            frm,
                                            result
                                        );
                                    }
                                },
                            });
                        }
                    );
                },
                __("Component Master")
            );
        }
    },
});

function show_generation_result(frm, result) {
    if (result.created_count === 0 && result.skipped_count === 0) {
        // No BOMs found - msgprint already shown by server
        return;
    }

    let details_html = "";
    if (result.details && result.details.length > 0) {
        let rows = result.details
            .map(function (d) {
                let status_class =
                    d.status === "Created" ? "text-success" : "text-muted";
                let link = d.component_master
                    ? '<a href="/app/project-component-master/' +
                      d.component_master +
                      '">' +
                      d.component_master +
                      "</a>"
                    : "-";
                return (
                    "<tr>" +
                    "<td>" + d.item_code + "</td>" +
                    "<td>" + d.bom + "</td>" +
                    '<td class="' + status_class + '">' + d.status + "</td>" +
                    "<td>" + link + "</td>" +
                    "</tr>"
                );
            })
            .join("");

        details_html =
            '<table class="table table-bordered table-sm" style="margin-top: 15px;">' +
            "<thead><tr>" +
            "<th>Item Code</th>" +
            "<th>BOM</th>" +
            "<th>Status</th>" +
            "<th>Component Master</th>" +
            "</tr></thead>" +
            "<tbody>" + rows + "</tbody>" +
            "</table>";
    }

    let d = new frappe.ui.Dialog({
        title: __("Component Masters Generated"),
        fields: [
            {
                fieldtype: "HTML",
                fieldname: "result_html",
                options:
                    '<div class="alert alert-success">' +
                    "<b>Created:</b> " + result.created_count +
                    " &nbsp;|&nbsp; <b>Skipped:</b> " + result.skipped_count +
                    " &nbsp;|&nbsp; <b>Total BOMs:</b> " +
                    (result.created_count + result.skipped_count) +
                    "</div>" +
                    details_html,
            },
        ],
        size: "large",
        primary_action_label: __("View Component Masters"),
        primary_action: function () {
            frappe.set_route("List", "Project Component Master", {
                project: frm.doc.name,
            });
            d.hide();
        },
    });

    d.show();
}

import frappe
from frappe.model.document import Document
import openpyxl
import io


class BOMUpload(Document):
    pass


@frappe.whitelist()
def create_boms(docname):
    doc = frappe.get_doc("BOM Upload", docname)
    return _create_boms(doc)


def _create_boms(doc):

    file_doc = frappe.get_doc("File", {"file_url": doc.bom_file})
    content = file_doc.get_content()

    wb = openpyxl.load_workbook(io.BytesIO(content), data_only=True)
    ws = wb.active

    rows = parse_rows(ws)
    tree = build_tree(rows)

    created = 0
    skipped = 0
    failed = 0
    errors = []

    for node in tree:
        try:
            created_flag = create_bom_recursive(node, doc.project)
            if created_flag:
                created += 1
            else:
                skipped += 1
        except Exception as e:
            failed += 1
            errors.append(f"{node['item_code']} → {str(e)}")

    return {
        "created": created,
        "skipped": skipped,
        "failed": failed,
        "errors": errors
    }


# ================= Excel helpers =================

def clean_code(code):
    if not code:
        return None
    return str(code).replace(".", "").strip()


def to_float(val, default=0):
    try:
        return float(val)
    except Exception:
        return default


def normalize_uom(uom):
    if not uom:
        return "Nos"
    u = str(uom).strip().upper()
    return {"NUMERI": "Nos", "PEZZI": "Nos", "METRI": "Meter"}.get(u, u)


# ================= Parse Excel =================

def parse_rows(ws):

    rows = []

    for r in range(3, ws.max_row + 1):

        code_raw = ws[f"C{r}"].value
        if not code_raw:
            continue

        position = ws[f"A{r}"].value or ws[f"B{r}"].value

        rows.append({
            "position": position,
            "item_code": clean_code(code_raw),
            "description": ws[f"D{r}"].value,
            "qty": to_float(ws[f"E{r}"].value, 1),
            "revision": ws[f"G{r}"].value,
            "material": ws[f"AC{r}"].value,
            "part_number": ws[f"AD{r}"].value,
            "weight": to_float(ws[f"AE{r}"].value, 0),
            "manufacturer": ws[f"AF{r}"].value,
            "treatment": ws[f"AL{r}"].value,
            "uom": normalize_uom(ws[f"AM{r}"].value),
            "level": int(ws[f"AR{r}"].value or 0),
            "children": []
        })

    return rows


# ================= Hierarchy =================

def build_tree(rows):

    stack = []
    roots = []

    for row in rows:

        while stack and stack[-1]["level"] >= row["level"]:
            stack.pop()

        if stack:
            stack[-1]["children"].append(row)
        else:
            roots.append(row)

        stack.append(row)

    return roots


# ================= Items =================

def ensure_item_exists(item_code, description, uom):

    if frappe.db.exists("Item", item_code):
        return

    item_name = description or item_code

    item = frappe.get_doc({
        "doctype": "Item",
        "item_code": item_code,
        "item_name": item_name,
        "description": item_name,
        "item_group": "All Item Groups",
        "stock_uom": uom or "Nos",
        "is_stock_item": 1,
        "is_purchase_item": 1,
        "is_sales_item": 0
    })

    item.insert(ignore_permissions=True)


# ================= BOM =================
def create_bom_recursive(node, project, root_level=None):
    """Create BOMs recursively, creating child BOMs first (bottom-up)"""

    if root_level is None:
        root_level = node["level"]

    ensure_item_exists(node["item_code"], node["description"], node["uom"])

    # First, recursively create BOMs for all children that have sub-assemblies
    for child in node["children"]:
        if child["children"]:  # If child has its own children, it needs a BOM
            create_bom_recursive(child, project, child["level"])

    # Check if BOM already exists
    existing = frappe.db.exists("BOM", {
        "item": node["item_code"],
        "is_active": 1,
        "is_default": 1
    })

    if existing:
        return False

    # Create BOM for current node
    bom = frappe.get_doc({
        "doctype": "BOM",
        "item": node["item_code"],
        "quantity": 1,
        "project": project,
        "is_active": 1,
        "is_default": 1
    })

    # Add ONLY direct children (not grandchildren)
    for child in node["children"]:
        ensure_item_exists(child["item_code"], child["description"], child["uom"])

        bom_item = {
            "item_code": child["item_code"],
            "qty": child["qty"],
            "uom": child["uom"],
            "custom_position": child["position"],
            "custom_revision_no": child["revision"],
            "custom_material": child["material"],
            "custom_part_number": child["part_number"],
            "custom_weight": child["weight"],
            "custom_manufacturer": child["manufacturer"],
            "custom_tipo_trattamento": child["treatment"],
            "custom_level_of_bom": 1  # Always 1 for direct children
        }

        # If child has its own BOM, link to it
        if child["children"]:
            child_bom = frappe.db.get_value("BOM", {
                "item": child["item_code"],
                "is_active": 1,
                "is_default": 1
            }, "name")
            if child_bom:
                bom_item["bom_no"] = child_bom

        bom.append("items", bom_item)

    bom.insert(ignore_permissions=True)
    bom.submit()

    return True

