frappe.ui.form.on('BOM Upload', {
    create_boms(frm) {
        if (!frm.doc.bom_file) {
            frappe.msgprint("Please attach a BOM Excel file first.");
            return;
        }

        frappe.call({
            method: 'clevertech.clevertech.doctype.bom_upload.bom_upload.create_boms',
            args: {
                docname: frm.doc.name
            },
            freeze: true,
            freeze_message: __('Creating BOMs...'),
            callback(r) {
                if (!r.message) {
                    frappe.msgprint({
                        title: __('Error'),
                        message: __('No response from server'),
                        indicator: 'red'
                    });
                    return;
                }

                const msg = r.message;
                let error_html = '';

                if (msg.errors && msg.errors.length > 0) {
                    error_html = '<br><br><strong>Errors:</strong><br>' + msg.errors.join('<br>');
                }

                frappe.msgprint({
                    title: __('BOM Import Result'),
                    message: `
                        <strong>BOMs Created:</strong> ${msg.created}<br>
                        <strong>BOMs Skipped:</strong> ${msg.skipped}<br>
                        <strong>Failed:</strong> ${msg.failed}
                        ${error_html}
                    `,
                    indicator: msg.failed > 0 ? 'orange' : 'green'
                });

                // Refresh the form to show any updates
                frm.reload_doc();
            },
            error(r) {
                frappe.msgprint({
                    title: __('Error'),
                    message: __('Failed to create BOMs. Please check the error log.'),
                    indicator: 'red'
                });
            }
        });
    }
});

import frappe

def before_validate(doc, method):
    # Fetch settings once
    settings = frappe.get_cached_doc("Quality Warehouse Settings")
    qc_accepted = settings.qc_accepted_warehouse or doc.set_warehouse
    default_store = settings.default_store_warehouse

    for row in doc.items:
        if not row.item_code:
            continue

        # Fetch only the required field
        requires_inspection = frappe.db.get_value(
            "Item",
            row.item_code,
            "inspection_required_before_purchase"
        )

        # Apply logic
        if requires_inspection:
            row.warehouse = qc_accepted
        else:
            row.warehouse = default_store
#    fetch_payment_terms(doc)

def fetch_payment_terms(doc):

    supplier_quotation_name = None

    # 1️⃣ Loop through PO Items and pick the first Supplier Quotation value
    for row in doc.items:
        if row.supplier_quotation:
            supplier_quotation_name = row.supplier_quotation
            break

    if not supplier_quotation_name:
        return  # No supplier quotation found, exit

    # 2️⃣ Fetch Supplier Quotation document
    sq = frappe.get_doc("Supplier Quotation", supplier_quotation_name)

    # 3️⃣ Set Payment Terms Template from Supplier Quotation
    if sq.custom_payment_terms_template:
        doc.payment_terms_template = sq.custom_payment_terms_template

    # 4️⃣ Copy child table data (custom_payment_schedule → payment_schedule)
    doc.payment_schedule.clear()

    for schedule in sq.custom_payment_schedule:
        doc.append("payment_schedule", {
            "payment_term": schedule.payment_term,
            "description": schedule.description,
            "due_date": schedule.due_date,
            "invoice_portion": schedule.invoice_portion,
            "payment_amount": schedule.payment_amount,
            "discount": schedule.discount
        })

import frappe

def on_submit(doc, method):
    pending = False

    for row in doc.items:
        # Check if item requires inspection
        requires_qi = frappe.db.get_value(
            "Item",
            row.item_code,
            "inspection_required_before_purchase"
        )

        if requires_qi:
            # Look for submitted QI for this PR + Item
            qi_exists = frappe.db.exists(
                "Quality Inspection",
                {
                    "reference_type": "Purchase Receipt",
                    "reference_name": doc.name,
                    "item_code": row.item_code,
                    "docstatus": 1
                }
            )
            if not qi_exists:
                pending = True
                break

    doc.db_set("custom_quality_status", "Pending" if pending else "Completed")

def before_validate(doc, method):
    # Skip warehouse changes if custom_bulk_quality_inspection_for_grn is filled
    if doc.get("custom_bulk_quality_inspection_for_grn"):
        return

    # Fetch settings once
    settings = frappe.get_cached_doc("Quality Warehouse Settings")
    qc_accepted = settings.qc_accepted_warehouse or doc.set_warehouse
    qc_rejected = settings.qc_rejected_warehouse or doc.rejected_warehouse
    default_store = settings.default_store_warehouse

    for row in doc.items:
        if not row.item_code:
            continue
        # Fetch only the required field
        requires_inspection = frappe.db.get_value(
            "Item",
            row.item_code,
            "inspection_required_before_purchase"
        )
        # Apply logic
        if requires_inspection:
            row.warehouse = qc_accepted
            row.rejected_warehouse = qc_rejected
        else:
            row.warehouse = default_store

def before_submit(doc, method):
    if doc.custom_bulk_quality_inspection_for_grn:
        if frappe.db.get_value("Bulk Quality Inspection", doc.custom_bulk_quality_inspection_for_grn, "docstatus") != 1:
            frappe.throw(f"Submit the Bulk Quality Inspection: {doc.custom_bulk_quality_inspection_for_grn}, before submitting the Purchase Receipt")


@frappe.whitelist()
def get_items_from_bulk_quality_inspection(bqi_doc):
    doc = frappe.get_doc("Bulk Quality Inspection", bqi_doc)
    qty_map = {}
    settings = frappe.get_cached_doc("Quality Warehouse Settings")
    qc_accepted = settings.qc_accepted_warehouse or doc.set_warehouse
    qc_rejected = settings.qc_rejected_warehouse or doc.rejected_warehouse
    default_store = settings.default_store_warehouse

    def add_rows(child_table):
        for row in child_table:
            if row.item_code:
                if row.item_code not in qty_map:
                    qty_map[row.item_code] = {"accepted_qty": 0, "rejected_qty": 0}

                if row.accepted_qty:
                    qty_map[row.item_code]["accepted_qty"] += row.accepted_qty

                if row.rejected_qty:
                    qty_map[row.item_code]["rejected_qty"] += row.rejected_qty

    add_rows(doc.grn_items_quality_reqd)
    #add_rows(doc.grn_items_quality_not_reqd)

    return [
        {
            "item_code": item_code, 
            "qty": qty_data["accepted_qty"],
            "rejected_qty": qty_data["rejected_qty"],
            "warehouse": default_store,
            "rejected_warehouse": qc_rejected
        }
        for item_code, qty_data in qty_map.items()
    ]

@frappe.whitelist()
def submit_bqi(bqi_doc, pr_name):
    bqi = frappe.get_doc("Bulk Quality Inspection", bqi_doc)
    if bqi.docstatus == 0:
        bqi.grn_name = pr_name
        bqi.submit()
        return {"success": True, "message": "BQI Document Submitted"}
    else:
        return {"success": True, "message": "BQI Already Submitted"}

