        + '<tr><td><i class="fa fa-minus-circle text-muted"></i> Skipped (Unchanged):</td>'
        + '<td><b>' + (result.skipped || 0) + '</b></td></tr>'
        + '<tr><td><i class="fa fa-times-circle text-danger"></i> Failed:</td>'
        + '<td><b>' + (result.failed || 0) + '</b></td></tr>'
        + '<tr class="text-primary"><td><i class="fa fa-cube"></i> Component Masters Created:</td>'
        + '<td><b>' + (result.component_masters_created || 0) + '</b></td></tr>'
        + '</table>'
        + errors_html
        + '</div>';

    frappe.msgprint({
        title: __('Success'),
        message: html,
        indicator: 'green'
    });
}

